// MARK: - Spy wrapping the real subscribeToOverviewUpdates mechanism for AC-RDNS-05

/// Validates that the subscription mechanism (overviewDidUpdate → forceRefresh)
/// works correctly. Uses the same Combine pattern as TrainingReadinessManager.subscribeToOverviewUpdates.
@MainActor
final class TrainingReadinessManagerTestable: ObservableObject {

    @Published var forceRefreshCallCount = 0
    private var cancellables = Set<AnyCancellable>()

    init(overviewRepository: any TrainingPlanV2Repository) {
        // Mirror the same subscription logic as TrainingReadinessManager.subscribeToOverviewUpdates
        overviewRepository.overviewDidUpdate
            .receive(on: DispatchQueue.main)
            .sink { [weak self] _ in
                Task { @MainActor [weak self] in
                    self?.forceRefreshCallCount += 1
                }
            }
            .store(in: &cancellables)
    }
}
